// In gameStore.equipFromStash(uid):
const item = sharedStash.find(i => i.uid === uid)
const slot = resolveEquipSlot(item) // ring → ring1 or ring2
const displaced = equipped[slot]
const newStash = sharedStash.filter(i => i.uid !== uid)
if (displaced) newStash.push(displaced)
invStore.setState(s => ({ equipped: { ...s.equipped, [slot]: item } }))
set({ sharedStash: newStash })

// Two tabs — EQUIPPED shows all 10 equip slots with STASH button
// STASH(N) shows sharedStash items with EQUIP or BAG button
const [tab, setTab] = useState<'equipped' | 'stash'>('equipped')
